+fn run_shadow_iteration(
+    args: &ShadowStartArgs,
+) -> Result<std::process::ExitStatus, std::io::Error> {
+    let exe = std::env::current_exe()?;
+
+    let mut cmd = std::process::Command::new(exe);
+    cmd.arg("--shadow")
+        .arg("--format")
+        .arg("json")
+        .arg("agent")
+        .arg("plan");
+    apply_shadow_plan_args(&mut cmd, args);
+
+    cmd.status()
+}
